function Modal({ isOpen, onClose, children }) {
  if (!isOpen) return null;
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(23,23,23,0.6)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 15, backdropFilter: "blur(8px)" }}>
      <div onClick={e => e.stopPropagation()} style={{ background: "rgba(223,223,223,1)", borderRadius: 24, maxWidth: 540, width: "100%", maxHeight: "90vh", overflowY: "auto", position: "relative" }}>
        <button onClick={onClose} style={{ position: "absolute", top: 20, right: 20, background: "rgba(23,23,23,0.08)", border: "none", width: 36, height: 36, borderRadius: "50%", cursor: "pointer", fontSize: 20, color: "rgba(23,23,23,0.6)", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.2s" }} onMouseEnter={e => { e.currentTarget.style.background = "rgba(23,23,23,0.15)"; }} onMouseLeave={e => { e.currentTarget.style.background = "rgba(23,23,23,0.08)"; }}>×</button>
        {children}
      </div>
    </div>
  );
}


